CONSTANTS_CODE = "API_KEY = 'PASTE_YOUR_POLYGON_API_KEY_HERE'\nUNDERLYING = 'I:SPX'\nPRICE_PROXY = 'SPY'\nUSE_REALTIME_SPOT = True\n\nMIN_OI = 1\nMIN_IV = 0.01\nPAGE_LIMIT = 250\nMAX_PAGES = 1000\nREQUEST_TIMEOUT = 30\n\nES_MULTIPLIER = 50\nMOVE_PCT_FOR_FLOW = 0.01\nSMA_FAST = 50\nSMA_SLOW = 200\nSPY_TO_SPX_MULTIPLIER = 10.0\n\nTRIGGER_LOOKBACK_BARS = 20\nBREAKOUT_VOLUME_MULTIPLIER = 1.20\nPULLBACK_VWAP_BUFFER_PCT = 0.0015\nSTOP_BUFFER_PCT = 0.0015\nTARGET_R_MULTIPLE = 2.0\nRISK_FREE_RATE = 0.05\nCONTRACT_SIZE = 100\n\nNEAR_SPOT_POINTS = 1500\nMAX_DTE_FOR_MODEL = 120\nLOCAL_FLIP_WINDOW = 500\nPARTICIPATION_THRESHOLD = 0.60\n\nLIVE_TRADING_MODE = True\n"
HELPERS_CODE = '# Shared state and helpers\nimport requests, pandas as pd, numpy as np, math, json, pytz\nfrom scipy.stats import norm\nfrom urllib.parse import urlencode, urlparse, parse_qsl, urlunparse\nfrom datetime import datetime, timedelta, timezone, time\nfrom pathlib import Path\n\ndef init_state():\n    global state\n    if \'state\' not in globals() or not isinstance(state, dict):\n        state = {}\n    state.setdefault(\'reports\', {})\n    state.setdefault(\'artifacts\', {})\n    state.setdefault(\'warnings\', [])\n    state.setdefault(\'config\', {})\n    return state\n\nstate = init_state()\n\ndef reset_section(section_name):\n    state[\'reports\'][section_name] = []\n\ndef log_line(section_name, line):\n    state[\'reports\'].setdefault(section_name, []).append(str(line))\n    print(line)\n\ndef safe_get(obj, *keys, default=None):\n    cur = obj\n    for key in keys:\n        if isinstance(cur, dict):\n            cur = cur.get(key, default)\n        elif isinstance(cur, list) and isinstance(key, int):\n            if 0 <= key < len(cur):\n                cur = cur[key]\n            else:\n                return default\n        else:\n            return default\n        if cur is None:\n            return default\n    return cur\n\ndef first_valid_numeric(values, min_value=None, max_value=None):\n    for v in values:\n        try:\n            x = float(v)\n            if min_value is not None and x < min_value:\n                continue\n            if max_value is not None and x > max_value:\n                continue\n            return x\n        except Exception:\n            continue\n    return None\n\ndef append_api_key(url, api_key):\n    parts = urlparse(url)\n    query = dict(parse_qsl(parts.query))\n    query[\'apiKey\'] = api_key\n    new_query = urlencode(query)\n    return urlunparse((parts.scheme, parts.netloc, parts.path, parts.params, new_query, parts.fragment))\n\ndef get_json(url):\n    r = requests.get(url, timeout=REQUEST_TIMEOUT)\n    r.raise_for_status()\n    return r.json()\n\ndef fmt_num(x, decimals=2):\n    try:\n        if x is None:\n            return "n/a"\n        if isinstance(x, float) and math.isnan(x):\n            return "n/a"\n        return f"{x:,.{decimals}f}"\n    except Exception:\n        return str(x)\n\ndef fmt_int(x):\n    try:\n        if x is None:\n            return "n/a"\n        if isinstance(x, float) and math.isnan(x):\n            return "n/a"\n        return f"{int(round(x)):,}"\n    except Exception:\n        return str(x)\n\ndef fmt_billions_int(x):\n    try:\n        if x is None:\n            return "n/a"\n        if isinstance(x, float) and math.isnan(x):\n            return "n/a"\n        return f"{int(round(x / 1e9)):,} $B"\n    except Exception:\n        return str(x)\n\ndef pct(part, whole):\n    return 0.0 if whole == 0 else 100.0 * part / whole\n\nny_tz = pytz.timezone("America/New_York")\n\ndef now_ny():\n    return datetime.now(tz=ny_tz)\n\ndef is_regular_session(dt_ny):\n    if dt_ny.weekday() >= 5:\n        return False\n    t = dt_ny.timetz().replace(tzinfo=None)\n    return (t >= time(9,30)) and (t <= time(16,0))\n\ndef previous_business_day(day):\n    d = day - timedelta(days=1)\n    while d.weekday() >= 5:\n        d -= timedelta(days=1)\n    return d\n\ndef get_intraday_session_with_fallback(symbol, api_key, lookback_days=7):\n    dt_ny = now_ny()\n    current_day = dt_ny.date()\n    current_session = is_regular_session(dt_ny)\n    checked_days = []\n    candidate_days = []\n    if current_session:\n        candidate_days.append(current_day)\n    d = previous_business_day(current_day) if current_session else current_day\n    for _ in range(lookback_days):\n        candidate_days.append(d)\n        d = previous_business_day(d)\n    seen = set()\n    candidate_days = [d for d in candidate_days if not (d in seen or seen.add(d))]\n    for day in candidate_days:\n        checked_days.append(str(day))\n        url = f\'https://api.polygon.io/v2/aggs/ticker/{symbol}/range/1/minute/{day}/{day}?adjusted=true&sort=asc&limit=5000&apiKey={api_key}\'\n        js = get_json(url)\n        results = js.get(\'results\', [])\n        if results:\n            mode = "realtime" if (day == current_day and current_session) else "delayed_fallback"\n            vwap_session_type = "current_session" if mode == "realtime" else "previous_session_fallback"\n            return pd.DataFrame(results), str(day), mode, vwap_session_type, checked_days, current_session\n    raise ValueError(f"No intraday data found for {symbol}. Days checked: {checked_days}")\n\n# defaults for rerun safety\nstate[\'config\'].update({\n    \'api_key_present\': API_KEY != \'PASTE_YOUR_POLYGON_API_KEY_HERE\',\n})\nlog_line("Initialization", "Shared state initialized.")\n'
SECTION_CODES = ['# 1) Load FULL chain safely and compute TRUE days_to_expiry\nstate = init_state()\nsection = "1) Load FULL chain safely and compute TRUE days_to_expiry"\nreset_section(section)\n\nurl = f\'https://api.polygon.io/v3/snapshot/options/{UNDERLYING}?limit={PAGE_LIMIT}&apiKey={API_KEY}\'\nall_rows, pages = [], 0\ntruncation_risk = False\nfinal_next_url_exists = False\n\nwhile url:\n    if pages >= MAX_PAGES:\n        truncation_risk = True\n        break\n    js = get_json(url)\n    data = js.get(\'results\', [])\n    if pages == 0 and not data:\n        raise ValueError("No results returned from options snapshot.")\n    for o in data:\n        d = o.get(\'details\', {})\n        q = o.get(\'last_quote\', {}) or {}\n        day = o.get(\'day\', {}) or {}\n        all_rows.append({\n            \'ticker\': o.get(\'ticker\'),\n            \'strike\': d.get(\'strike_price\'),\n            \'expiry\': d.get(\'expiration_date\'),\n            \'type\': d.get(\'contract_type\'),\n            \'oi\': d.get(\'open_interest\', o.get(\'open_interest\', 0)) or o.get(\'open_interest\', 0) or 0,\n            \'volume\': day.get(\'volume\', 0) or 0,\n            \'iv\': o.get(\'implied_volatility\', 0.0) or 0.0,\n            \'bid\': q.get(\'bid\'),\n            \'ask\': q.get(\'ask\'),\n            \'mid\': q.get(\'midpoint\'),\n            \'days_to_expiry_raw\': d.get(\'days_to_expiration\'),\n        })\n    next_url = js.get(\'next_url\')\n    final_next_url_exists = next_url is not None\n    url = append_api_key(next_url, API_KEY) if next_url else None\n    pages += 1\n\nfull_df = pd.DataFrame(all_rows)\nfor col in [\'strike\',\'oi\',\'volume\',\'iv\',\'bid\',\'ask\',\'mid\',\'days_to_expiry_raw\']:\n    full_df[col] = pd.to_numeric(full_df[col], errors=\'coerce\')\n\nfull_df[\'expiry\'] = pd.to_datetime(full_df[\'expiry\'], errors=\'coerce\').dt.tz_localize(None).dt.normalize()\ntoday_ny = pd.Timestamp(now_ny().date())\nfull_df[\'days_to_expiry\'] = (full_df[\'expiry\'] - today_ny).dt.days\n\nexpiry_sample = full_df[[\'expiry\',\'days_to_expiry\']].drop_duplicates().sort_values(\'expiry\').head(30)\n\nstate.update({\n    \'full_df\': full_df,\n    \'pages\': pages,\n    \'truncation_risk\': truncation_risk,\n    \'final_next_url_exists\': final_next_url_exists,\n    \'expiry_sample\': expiry_sample,\n})\n\nlog_line(section, f"Pages fetched: {pages}")\nlog_line(section, f"Rows returned: {len(full_df)}")\nlog_line(section, "")\nlog_line(section, "Option type counts:")\nlog_line(section, full_df[\'type\'].value_counts(dropna=False).to_string())\nlog_line(section, "")\nlog_line(section, "True days_to_expiry summary:")\nlog_line(section, full_df[\'days_to_expiry\'].describe().to_string())\nlog_line(section, "")\nlog_line(section, "Unique expiry / days_to_expiry sample:")\nlog_line(section, expiry_sample.to_string(index=False))\n', '# 2) Resolve spot with hierarchy: SPX snapshot -> SPY proxy -> parity\nstate = init_state()\nsection = "2) Resolve spot with hierarchy: SPX snapshot -> SPY proxy -> parity"\nreset_section(section)\n\nfull_df = state.get(\'full_df\')\nif full_df is None:\n    raise ValueError("full_df missing. Run cell 1 first.")\n\nwork = full_df.copy()\nwork[\'price\'] = work[\'mid\']\nmask = work[\'price\'].isna() & work[\'bid\'].notna() & work[\'ask\'].notna()\nwork.loc[mask, \'price\'] = (work.loc[mask, \'bid\'] + work.loc[mask, \'ask\']) / 2\ncalls = work[(work[\'type\'] == \'call\') & work[\'price\'].notna()]\nputs = work[(work[\'type\'] == \'put\') & work[\'price\'].notna()]\nmerged = calls.merge(puts, on=[\'strike\',\'expiry\'], suffixes=(\'_c\',\'_p\'))\nmerged[\'spot_est\'] = merged[\'strike\'] + (merged[\'price_c\'] - merged[\'price_p\'])\nlo, hi = merged[\'spot_est\'].quantile([0.10, 0.90])\nparity_spot = float(merged[(merged[\'spot_est\'] >= lo) & (merged[\'spot_est\'] <= hi)][\'spot_est\'].median())\n\nspot_source = \'parity_only\'\nS = parity_spot\n\nif USE_REALTIME_SPOT:\n    endpoints = [\n        f\'https://api.polygon.io/v2/snapshot/locale/us/markets/indices/tickers/{UNDERLYING}?apiKey={API_KEY}\',\n        f\'https://api.polygon.io/v3/snapshot/indices?ticker.any_of={UNDERLYING}&apiKey={API_KEY}\',\n        f\'https://api.polygon.io/v3/snapshot/indices/{UNDERLYING}?apiKey={API_KEY}\',\n    ]\n    got = False\n    for ep in endpoints:\n        try:\n            js = get_json(ep)\n            candidates = [\n                safe_get(js, \'ticker\', \'lastTrade\', \'p\'),\n                safe_get(js, \'ticker\', \'value\'),\n                safe_get(js, \'results\', 0, \'value\'),\n                safe_get(js, \'results\', 0, \'session\', \'close\'),\n                safe_get(js, \'results\', \'value\'),\n                safe_get(js, \'results\', \'session\', \'close\'),\n            ]\n            val = first_valid_numeric(candidates, min_value=1000, max_value=10000)\n            if val is not None:\n                S = val\n                spot_source = \'realtime_index\'\n                got = True\n                break\n        except Exception:\n            pass\n\n    if not got:\n        for ep in [\n            f\'https://api.polygon.io/v2/last/trade/{PRICE_PROXY}?apiKey={API_KEY}\',\n            f\'https://api.polygon.io/v2/snapshot/locale/us/markets/stocks/tickers/{PRICE_PROXY}?apiKey={API_KEY}\',\n        ]:\n            try:\n                js = get_json(ep)\n                candidates = [\n                    safe_get(js, \'results\', \'p\'),\n                    safe_get(js, \'ticker\', \'lastTrade\', \'p\'),\n                    safe_get(js, \'ticker\', \'min\', \'c\'),\n                    safe_get(js, \'ticker\', \'day\', \'c\'),\n                ]\n                val = first_valid_numeric(candidates, min_value=10, max_value=2000)\n                if val is not None:\n                    S = val * SPY_TO_SPX_MULTIPLIER\n                    spot_source = \'spy_proxy\'\n                    break\n            except Exception:\n                pass\n\nstate.update({\'S\': S, \'parity_spot\': parity_spot, \'spot_source\': spot_source})\n\nlog_line(section, f"SPX spot used: {S:,.2f}")\nlog_line(section, f"Parity spot: {parity_spot:,.2f}")\nlog_line(section, f"Spot source: {spot_source}")\n', '# 2A) Chain capture diagnostics\nstate = init_state()\nsection = "2A) Chain capture diagnostics"\nreset_section(section)\n\nfull_df = state.get(\'full_df\')\nS = state.get(\'S\')\nif full_df is None or S is None:\n    raise ValueError("Missing prerequisites. Run cells 1 and 2 first.")\n\nfull_rows = len(full_df)\nfull_oi = float(full_df[\'oi\'].fillna(0).sum())\n\nmodel_df = full_df.copy()\nmodel_df = model_df[\n    model_df[\'strike\'].notna() &\n    model_df[\'type\'].isin([\'call\',\'put\']) &\n    (model_df[\'oi\'].fillna(0) >= MIN_OI) &\n    (model_df[\'iv\'].fillna(0) >= MIN_IV)\n].copy()\n\ndownsample_mask = (\n    ((model_df[\'strike\'] - S).abs() <= NEAR_SPOT_POINTS) &\n    (model_df[\'days_to_expiry\'] <= MAX_DTE_FOR_MODEL)\n) | (model_df[\'days_to_expiry\'] == 0)\n\nmodel_df = model_df[downsample_mask].copy()\n\nmodel_rows = len(model_df)\nmodel_oi = float(model_df[\'oi\'].fillna(0).sum())\n\ncapture_pct_rows = pct(model_rows, full_rows)\ncapture_pct_oi = pct(model_oi, full_oi)\n\nstate.update({\n    \'model_df\': model_df,\n    \'full_rows\': full_rows,\n    \'full_oi\': full_oi,\n    \'model_rows\': model_rows,\n    \'model_oi\': model_oi,\n    \'capture_pct_rows\': capture_pct_rows,\n    \'capture_pct_oi\': capture_pct_oi,\n})\n\nlog_line(section, f"Full chain rows fetched: {full_rows:,}")\nlog_line(section, f"Model rows retained after downsampling: {model_rows:,}")\nlog_line(section, f"Row capture %: {capture_pct_rows:.2f}%")\nlog_line(section, f"Open interest capture %: {capture_pct_oi:.2f}%")\nlog_line(section, f"Truncation risk exists: {state.get(\'truncation_risk\')}")\nlog_line(section, f"Pagination ended naturally: {not state.get(\'final_next_url_exists\') and not state.get(\'truncation_risk\')}")\nlog_line(section, f"Downsampling rule: abs(strike - spot) <= {NEAR_SPOT_POINTS} and DTE <= {MAX_DTE_FOR_MODEL}, always keep 0DTE")\n', '# 3) Price proxy data for SMA / VWAP + intraday edge upgrades\nstate = init_state()\nsection = "3) Price proxy data for SMA / VWAP"\nreset_section(section)\n\nS = state.get(\'S\')\nif S is None:\n    raise ValueError("Spot missing. Run cell 2 first.")\n\nend = now_ny().date()\nstart = end - timedelta(days=520)\n\ndaily = pd.DataFrame(get_json(\n    f\'https://api.polygon.io/v2/aggs/ticker/{PRICE_PROXY}/range/1/day/{start}/{end}?adjusted=true&sort=asc&limit=5000&apiKey={API_KEY}\'\n).get(\'results\', []))\ndaily[\'datetime\'] = pd.to_datetime(daily[\'t\'], unit=\'ms\', utc=True)\ndaily[\'close\'] = pd.to_numeric(daily[\'c\'], errors=\'coerce\')\ndaily[\'volume\'] = pd.to_numeric(daily[\'v\'], errors=\'coerce\')\ndaily = daily[[\'datetime\',\'close\',\'volume\']].dropna().reset_index(drop=True)\n\nintraday_raw, intraday_session_date, market_data_mode, vwap_session_type, intraday_days_checked, current_session_open = get_intraday_session_with_fallback(PRICE_PROXY, API_KEY)\nintraday = intraday_raw.copy()\nintraday[\'datetime\'] = pd.to_datetime(intraday[\'t\'], unit=\'ms\', utc=True)\nintraday[\'open\'] = pd.to_numeric(intraday[\'o\'], errors=\'coerce\')\nintraday[\'high\'] = pd.to_numeric(intraday[\'h\'], errors=\'coerce\')\nintraday[\'low\'] = pd.to_numeric(intraday[\'l\'], errors=\'coerce\')\nintraday[\'close\'] = pd.to_numeric(intraday[\'c\'], errors=\'coerce\')\nintraday[\'volume\'] = pd.to_numeric(intraday[\'v\'], errors=\'coerce\')\nintraday = intraday[[\'datetime\',\'open\',\'high\',\'low\',\'close\',\'volume\']].dropna().reset_index(drop=True)\n\nlive_spy_last = np.nan\nlive_spy_last_source = "unavailable"\nfor ep in [\n    f\'https://api.polygon.io/v2/last/trade/{PRICE_PROXY}?apiKey={API_KEY}\',\n    f\'https://api.polygon.io/v2/snapshot/locale/us/markets/stocks/tickers/{PRICE_PROXY}?apiKey={API_KEY}\',\n]:\n    try:\n        js = get_json(ep)\n        candidates = [\n            safe_get(js, \'results\', \'p\'),\n            safe_get(js, \'ticker\', \'lastTrade\', \'p\'),\n            safe_get(js, \'ticker\', \'min\', \'c\'),\n            safe_get(js, \'ticker\', \'day\', \'c\'),\n        ]\n        val = first_valid_numeric(candidates, min_value=10, max_value=2000)\n        if val is not None:\n            live_spy_last = float(val)\n            live_spy_last_source = ep.split(\'/v2/\')[-1].split(\'?\')[0]\n            break\n    except Exception:\n        pass\n\ntrade_flow_bias = np.nan\ntrade_flow_bias_recent = np.nan\ntrade_flow_bias_weighted = np.nan\ntrade_count_used = 0\ntrade_bias_label = "unavailable"\ntrade_bias_divergence = "Unknown"\ntry:\n    trade_day = intraday_session_date\n    trades_url = f\'https://api.polygon.io/v3/trades/{PRICE_PROXY}?timestamp={trade_day}&order=asc&limit=50000&sort=timestamp&apiKey={API_KEY}\'\n    trades_js = get_json(trades_url)\n    trades = pd.DataFrame(trades_js.get(\'results\', []))\n    if not trades.empty:\n        trade_price_col = \'price\' if \'price\' in trades.columns else (\'p\' if \'p\' in trades.columns else None)\n        trade_size_col = \'size\' if \'size\' in trades.columns else (\'s\' if \'s\' in trades.columns else None)\n        if trade_price_col is not None:\n            trades[\'price\'] = pd.to_numeric(trades[trade_price_col], errors=\'coerce\')\n            if trade_size_col is not None:\n                trades[\'size\'] = pd.to_numeric(trades[trade_size_col], errors=\'coerce\').fillna(1.0)\n            else:\n                trades[\'size\'] = 1.0\n            trades = trades[[\'price\',\'size\']].dropna().tail(5000).reset_index(drop=True)\n            if len(trades) >= 2:\n                trades[\'price_change\'] = trades[\'price\'].diff()\n                trades[\'signed_size\'] = np.where(trades[\'price_change\'] >= 0, trades[\'size\'], -trades[\'size\'])\n\n                def _bias(df):\n                    buy_size = df.loc[df[\'signed_size\'] > 0, \'signed_size\'].sum()\n                    sell_size = -df.loc[df[\'signed_size\'] < 0, \'signed_size\'].sum()\n                    denom = buy_size + sell_size\n                    return (buy_size / denom) if denom > 0 else np.nan\n\n                trade_flow_bias = _bias(trades)\n                recent_n = min(750, len(trades))\n                trade_flow_bias_recent = _bias(trades.tail(recent_n).reset_index(drop=True))\n                if np.isnan(trade_flow_bias) and not np.isnan(trade_flow_bias_recent):\n                    trade_flow_bias_weighted = trade_flow_bias_recent\n                elif np.isnan(trade_flow_bias_recent) and not np.isnan(trade_flow_bias):\n                    trade_flow_bias_weighted = trade_flow_bias\n                elif not np.isnan(trade_flow_bias) and not np.isnan(trade_flow_bias_recent):\n                    trade_flow_bias_weighted = 0.35 * trade_flow_bias + 0.65 * trade_flow_bias_recent\n\n                trade_count_used = int(len(trades))\n                bias_for_label = trade_flow_bias_weighted if not np.isnan(trade_flow_bias_weighted) else trade_flow_bias\n                if not np.isnan(bias_for_label):\n                    if bias_for_label >= 0.55:\n                        trade_bias_label = "BUY DOMINANT"\n                    elif bias_for_label <= 0.45:\n                        trade_bias_label = "SELL DOMINANT"\n                    else:\n                        trade_bias_label = "BALANCED"\n\n                if not np.isnan(trade_flow_bias) and not np.isnan(trade_flow_bias_recent):\n                    if abs(trade_flow_bias_recent - trade_flow_bias) <= 0.03:\n                        trade_bias_divergence = "Stable"\n                    elif trade_flow_bias_recent > trade_flow_bias:\n                        trade_bias_divergence = "Recent Buy Strength"\n                    else:\n                        trade_bias_divergence = "Recent Sell Strength"\nexcept Exception:\n    pass\n\nspread = np.nan\nspread_regime = "Unavailable"\ntry:\n    quote_js = get_json(f\'https://api.polygon.io/v3/quotes/{PRICE_PROXY}?limit=1&order=desc&sort=timestamp&apiKey={API_KEY}\')\n    quote_results = quote_js.get(\'results\', [])\n    if quote_results:\n        q0 = quote_results[0]\n        bid = first_valid_numeric([q0.get(\'bid_price\'), q0.get(\'bp\')], min_value=0)\n        ask = first_valid_numeric([q0.get(\'ask_price\'), q0.get(\'ap\')], min_value=0)\n        if bid is not None and ask is not None and ask >= bid:\n            spread = ask - bid\n            spread_regime = "Tight" if spread <= 0.02 else ("Normal" if spread <= 0.05 else "Wide")\nexcept Exception:\n    pass\n\ndaily[\'SMA_50\'] = daily[\'close\'].rolling(SMA_FAST).mean()\ndaily[\'SMA_200\'] = daily[\'close\'].rolling(SMA_SLOW).mean()\nintraday[\'cum_vol\'] = intraday[\'volume\'].cumsum()\nintraday[\'cum_vol_px\'] = (intraday[\'close\'] * intraday[\'volume\']).cumsum()\nintraday[\'VWAP\'] = intraday[\'cum_vol_px\'] / intraday[\'cum_vol\']\nintraday[\'roc_5\'] = intraday[\'close\'].pct_change(5)\nintraday[\'range_expansion\'] = (intraday[\'high\'] - intraday[\'low\']) / intraday[\'close\'].replace(0, np.nan)\nintraday[\'velocity_1m\'] = intraday[\'close\'].pct_change(1)\nintraday[\'velocity_5m\'] = intraday[\'close\'].pct_change(5)\n\nlatest_daily = daily.iloc[-1]\nlatest_intraday = intraday.iloc[-1]\nsma_regime = \'BULL\' if latest_daily[\'SMA_50\'] > latest_daily[\'SMA_200\'] else \'BEAR\'\nvwap_position = \'ABOVE\' if latest_intraday[\'close\'] > latest_intraday[\'VWAP\'] else \'BELOW\'\n\nstate.update({\n    \'daily\': daily,\n    \'intraday\': intraday,\n    \'intraday_session_date\': intraday_session_date,\n    \'market_data_mode\': market_data_mode,\n    \'vwap_session_type\': vwap_session_type,\n    \'intraday_days_checked\': intraday_days_checked,\n    \'current_session_open\': current_session_open,\n    \'live_spy_last\': live_spy_last,\n    \'live_spy_last_source\': live_spy_last_source,\n    \'trade_flow_bias\': trade_flow_bias,\n    \'trade_flow_bias_recent\': trade_flow_bias_recent,\n    \'trade_flow_bias_weighted\': trade_flow_bias_weighted,\n    \'trade_count_used\': trade_count_used,\n    \'trade_bias_label\': trade_bias_label,\n    \'trade_bias_divergence\': trade_bias_divergence,\n    \'spread\': spread,\n    \'spread_regime\': spread_regime,\n    \'latest_daily\': latest_daily,\n    \'latest_intraday\': latest_intraday,\n    \'sma_regime\': sma_regime,\n    \'vwap_position\': vwap_position,\n    \'velocity_1m\': float(latest_intraday[\'velocity_1m\']) if pd.notna(latest_intraday[\'velocity_1m\']) else 0.0,\n    \'velocity_5m\': float(latest_intraday[\'velocity_5m\']) if pd.notna(latest_intraday[\'velocity_5m\']) else 0.0,\n    \'range_expansion_latest\': float(latest_intraday[\'range_expansion\']) if pd.notna(latest_intraday[\'range_expansion\']) else 0.0,\n})\n\nlog_line(section, f"SMA Regime: {sma_regime}")\nlog_line(section, f"VWAP Position: {vwap_position}")\nlog_line(section, f"SPY Session last used for VWAP: {latest_intraday[\'close\']:,.2f}")\nlog_line(section, f"SPY Live last quote: {live_spy_last:,.2f}" if not np.isnan(live_spy_last) else "SPY Live last quote: n/a")\nlog_line(section, f"SPY Live last quote source: {live_spy_last_source}")\nlog_line(section, f"{PRICE_PROXY} VWAP: {latest_intraday[\'VWAP\']:,.2f}")\nlog_line(section, f"SMA50: {latest_daily[\'SMA_50\']:,.2f}")\nlog_line(section, f"SMA200: {latest_daily[\'SMA_200\']:,.2f}")\nlog_line(section, f"Market hours open now (NY): {current_session_open}")\nlog_line(section, f"Market data mode: {market_data_mode}")\nlog_line(section, f"VWAP session type: {vwap_session_type}")\nlog_line(section, f"Intraday session date used: {intraday_session_date}")\nlog_line(section, f"Intraday days checked: {intraday_days_checked}")\nlog_line(section, f"Trade flow bias (session): {trade_flow_bias:,.4f}" if not np.isnan(trade_flow_bias) else "Trade flow bias (session): n/a")\nlog_line(section, f"Trade flow bias (recent): {trade_flow_bias_recent:,.4f}" if not np.isnan(trade_flow_bias_recent) else "Trade flow bias (recent): n/a")\nlog_line(section, f"Trade flow bias (weighted): {trade_flow_bias_weighted:,.4f}" if not np.isnan(trade_flow_bias_weighted) else "Trade flow bias (weighted): n/a")\nlog_line(section, f"Trade bias label: {trade_bias_label}")\nlog_line(section, f"Trade bias divergence: {trade_bias_divergence}")\nlog_line(section, f"Trade count used: {trade_count_used}")\nlog_line(section, f"Spread: {spread:,.4f}" if not np.isnan(spread) else "Spread: n/a")\nlog_line(section, f"Spread regime: {spread_regime}")\nlog_line(section, f"Intraday velocity (1m): {state[\'velocity_1m\']:.4%}")\nlog_line(section, f"Intraday velocity (5m): {state[\'velocity_5m\']:.4%}")\nlog_line(section, f"Range expansion: {state[\'range_expansion_latest\']:.4%}")\n', '# 4) Gamma engine + corrected 0DTE outputs + edge upgrades\nstate = init_state()\nsection = "4) Gamma engine + corrected 0DTE outputs"\nreset_section(section)\n\nmodel_df = state.get(\'model_df\')\nS = state.get(\'S\')\nif model_df is None or S is None:\n    raise ValueError("Missing prerequisites. Run cells 2 and 2A first.")\n\ndf_clean = model_df.copy()\n\ndef _d1(S, K, T, sigma, r=RISK_FREE_RATE):\n    return (np.log(S / K) + (r + 0.5 * sigma**2) * T) / (sigma * np.sqrt(T))\n\ndef gamma(S, K, T, sigma, r=RISK_FREE_RATE):\n    if T <= 0 or sigma <= 0 or S <= 0 or K <= 0:\n        return 0.0\n    return norm.pdf(_d1(S, K, T, sigma, r)) / (S * sigma * np.sqrt(T))\n\ndef vanna(S, K, T, sigma, r=RISK_FREE_RATE):\n    if T <= 0 or sigma <= 0 or S <= 0 or K <= 0:\n        return 0.0\n    d1 = _d1(S, K, T, sigma, r)\n    d2 = d1 - sigma * np.sqrt(T)\n    return -norm.pdf(d1) * d2 / sigma\n\ndef charm_call(S, K, T, sigma, r=RISK_FREE_RATE):\n    if T <= 0 or sigma <= 0 or S <= 0 or K <= 0:\n        return 0.0\n    d1 = _d1(S, K, T, sigma, r)\n    d2 = d1 - sigma * np.sqrt(T)\n    term = 2 * r * T - d2 * sigma * np.sqrt(T)\n    return -norm.pdf(d1) * term / (2 * T * sigma * np.sqrt(T))\n\ngex_df = df_clean.copy()\ngex_df[\'gex\'] = 0.0\ngex_df[\'vex\'] = 0.0\ngex_df[\'cex\'] = 0.0\ngex_df[\'call_gex_pos\'] = 0.0\ngex_df[\'put_gex_abs\'] = 0.0\n\nfor idx, row in gex_df.iterrows():\n    T = max(max(row[\'days_to_expiry\'], 0) / 365, 1/365)\n    gexp = gamma(S, row[\'strike\'], T, row[\'iv\']) * row[\'oi\'] * CONTRACT_SIZE * (S ** 2)\n    vexp = vanna(S, row[\'strike\'], T, row[\'iv\']) * row[\'oi\'] * CONTRACT_SIZE * S\n    cexp = charm_call(S, row[\'strike\'], T, row[\'iv\']) * row[\'oi\'] * CONTRACT_SIZE * S\n    if row[\'type\'] == \'put\':\n        gexp *= -1\n        vexp *= -1\n        cexp *= -1\n        gex_df.at[idx, \'put_gex_abs\'] = abs(gexp)\n    else:\n        gex_df.at[idx, \'call_gex_pos\'] = max(gexp, 0)\n    gex_df.at[idx, \'gex\'] = gexp\n    gex_df.at[idx, \'vex\'] = vexp\n    gex_df.at[idx, \'cex\'] = cexp\n\ncurve = gex_df.groupby(\'strike\', as_index=False)[\'gex\'].sum().sort_values(\'strike\')\nlocal_curve = curve[(curve[\'strike\'] > S - LOCAL_FLIP_WINDOW) & (curve[\'strike\'] < S + LOCAL_FLIP_WINDOW)].copy()\nlocal_curve[\'cum\'] = local_curve[\'gex\'].cumsum()\nlocal_curve[\'sign\'] = np.sign(local_curve[\'cum\'])\nlocal_curve[\'sign_shift\'] = local_curve[\'sign\'].shift(1)\nflip_candidates = local_curve[local_curve[\'sign\'] != local_curve[\'sign_shift\']].copy()\nif not flip_candidates.empty:\n    flip_candidates[\'dist_from_spot\'] = (flip_candidates[\'strike\'] - S).abs()\n    flip = float(flip_candidates.sort_values([\'dist_from_spot\', \'strike\']).iloc[0][\'strike\'])\nelse:\n    flip = np.nan\n\ncall_wall = float(df_clean[df_clean[\'type\']==\'call\'].groupby(\'strike\')[\'oi\'].sum().idxmax()) if not df_clean[df_clean[\'type\']==\'call\'].empty else np.nan\nput_wall = float(df_clean[df_clean[\'type\']==\'put\'].groupby(\'strike\')[\'oi\'].sum().idxmax()) if not df_clean[df_clean[\'type\']==\'put\'].empty else np.nan\n\ncall_gex_wall_series = gex_df[gex_df[\'type\']==\'call\'].groupby(\'strike\')[\'call_gex_pos\'].sum()\nput_gex_wall_series = gex_df[gex_df[\'type\']==\'put\'].groupby(\'strike\')[\'put_gex_abs\'].sum()\ncall_gex_wall = float(call_gex_wall_series.idxmax()) if not call_gex_wall_series.empty else np.nan\nput_gex_wall = float(put_gex_wall_series.idxmax()) if not put_gex_wall_series.empty else np.nan\n\nimpact = gex_df.groupby(\'strike\', as_index=False)[\'gex\'].sum()\nimpact[\'abs_gex\'] = impact[\'gex\'].abs()\nimpact[\'dist_from_spot\'] = (impact[\'strike\'] - S).abs()\nimpact_top = impact.sort_values([\'abs_gex\'], ascending=False).head(5).copy()\ntrue_pin_level = float(impact_top.sort_values([\'dist_from_spot\',\'abs_gex\'], ascending=[True, False]).iloc[0][\'strike\']) if not impact_top.empty else np.nan\n\ntop_hedging_impact = impact.sort_values(\'abs_gex\', ascending=False).head(5).copy()\ntop_hedging_impact[\'rank\'] = range(1, len(top_hedging_impact)+1)\ntop_hedging_impact = top_hedging_impact[[\'rank\',\'strike\',\'gex\',\'abs_gex\',\'dist_from_spot\']]\ntop_hedging_impact_display = top_hedging_impact.copy()\ntop_hedging_impact_display[\'gex\'] = top_hedging_impact_display[\'gex\'].apply(fmt_billions_int)\ntop_hedging_impact_display[\'abs_gex\'] = top_hedging_impact_display[\'abs_gex\'].apply(fmt_billions_int)\n\nzero_dte = gex_df[gex_df[\'days_to_expiry\'] == 0].copy()\nzero_curve = zero_dte.groupby(\'strike\', as_index=False)[\'gex\'].sum().sort_values(\'strike\')\nzero_local_curve = zero_curve[(zero_curve[\'strike\'] > S - LOCAL_FLIP_WINDOW) & (zero_curve[\'strike\'] < S + LOCAL_FLIP_WINDOW)].copy()\nif not zero_local_curve.empty:\n    zero_local_curve[\'cum\'] = zero_local_curve[\'gex\'].cumsum()\n    zero_local_curve[\'sign\'] = np.sign(zero_local_curve[\'cum\'])\n    zero_local_curve[\'sign_shift\'] = zero_local_curve[\'sign\'].shift(1)\n    zero_flip_candidates = zero_local_curve[zero_local_curve[\'sign\'] != zero_local_curve[\'sign_shift\']].copy()\n    if not zero_flip_candidates.empty:\n        zero_flip_candidates[\'dist_from_spot\'] = (zero_flip_candidates[\'strike\'] - S).abs()\n        zero_flip = float(zero_flip_candidates.sort_values([\'dist_from_spot\', \'strike\']).iloc[0][\'strike\'])\n    else:\n        zero_flip = np.nan\nelse:\n    zero_flip = np.nan\n\ntotal_gex = float(gex_df[\'gex\'].sum())\nzero_dte_gex = float(zero_dte[\'gex\'].sum()) if not zero_dte.empty else 0.0\ntotal_es_flow = (total_gex * MOVE_PCT_FOR_FLOW) / (ES_MULTIPLIER * S) if S > 0 else 0.0\nzero_dte_es_flow = (zero_dte_gex * MOVE_PCT_FOR_FLOW) / (ES_MULTIPLIER * S) if S > 0 else 0.0\ngamma_regime = \'POSITIVE\' if total_gex > 0 else \'NEGATIVE\'\nflip_distance = abs(flip - S) if not np.isnan(flip) else np.nan\nzero_flip_distance = abs(zero_flip - S) if not np.isnan(zero_flip) else np.nan\nflip_context = \'NO LOCAL FLIP (one-sided gamma near spot)\' if (not np.isnan(flip_distance) and flip_distance > 200) else \'LOCAL FLIP PRESENT\'\nzero_flip_context = \'NO LOCAL 0DTE FLIP (one-sided 0DTE gamma near spot)\' if (not np.isnan(zero_flip_distance) and zero_flip_distance > 200) else \'LOCAL 0DTE FLIP PRESENT\'\n\nzero_dte_share = abs(zero_dte_gex / total_gex) if total_gex != 0 else 0.0\nintraday_regime = "0DTE Dominant" if zero_dte_share > 0.25 else "Structural Gamma"\n\npin_distance_spx = abs(S - true_pin_level) if not np.isnan(true_pin_level) else np.nan\npin_pressure = float(np.exp(-pin_distance_spx / 50.0)) if not np.isnan(pin_distance_spx) else np.nan\npin_pressure_label = "High" if (not np.isnan(pin_pressure) and pin_pressure >= 0.60) else ("Moderate" if (not np.isnan(pin_pressure) and pin_pressure >= 0.25) else "Low")\n\nstate.update({\n    \'gex_df\': gex_df,\n    \'flip\': flip,\n    \'zero_flip\': zero_flip,\n    \'call_wall\': call_wall,\n    \'put_wall\': put_wall,\n    \'call_gex_wall\': call_gex_wall,\n    \'put_gex_wall\': put_gex_wall,\n    \'true_pin_level\': true_pin_level,\n    \'top_hedging_impact\': top_hedging_impact,\n    \'top_hedging_impact_display\': top_hedging_impact_display,\n    \'total_gex\': total_gex,\n    \'zero_dte_gex\': zero_dte_gex,\n    \'total_es_flow\': total_es_flow,\n    \'zero_dte_es_flow\': zero_dte_es_flow,\n    \'gamma_regime\': gamma_regime,\n    \'flip_context\': flip_context,\n    \'zero_flip_context\': zero_flip_context,\n    \'pin_pressure\': pin_pressure,\n    \'pin_pressure_label\': pin_pressure_label,\n    \'intraday_regime\': intraday_regime,\n    \'zero_dte_share\': zero_dte_share,\n})\n\nlog_line(section, f"Gamma Regime: {gamma_regime}")\nlog_line(section, f"Gamma Flip (local robust): {flip:,.2f}" if not np.isnan(flip) else "Gamma Flip (local robust): n/a")\nlog_line(section, f"Gamma Flip Context: {flip_context}")\nlog_line(section, f"0DTE Flip (local robust): {zero_flip:,.2f}" if not np.isnan(zero_flip) else "0DTE Flip (local robust): n/a")\nlog_line(section, f"0DTE Flip Context: {zero_flip_context}")\nlog_line(section, f"Call Wall (raw OI): {call_wall:,.0f}")\nlog_line(section, f"Put Wall (raw OI): {put_wall:,.0f}")\nlog_line(section, f"Call Wall (GEX-weighted): {call_gex_wall:,.0f}")\nlog_line(section, f"Put Wall (GEX-weighted): {put_gex_wall:,.0f}")\nlog_line(section, f"True Pin Level: {true_pin_level:,.0f}")\nlog_line(section, f"Pin Pressure: {pin_pressure:.4f}" if not np.isnan(pin_pressure) else "Pin Pressure: n/a")\nlog_line(section, f"Pin Pressure Label: {pin_pressure_label}")\nlog_line(section, f"Intraday Regime: {intraday_regime}")\nlog_line(section, f"Total GEX: {total_gex/1e9:,.2f}B")\nlog_line(section, f"0DTE GEX: {zero_dte_gex/1e9:,.2f}B")\nlog_line(section, f"Total ES Flow /1%: {total_es_flow:,.0f}")\nlog_line(section, f"0DTE ES Flow /1%: {zero_dte_es_flow:,.0f}")\nlog_line(section, f"Total Vanna: {gex_df[\'vex\'].sum()/1e9:,.2f}B")\nlog_line(section, f"Total Charm: {gex_df[\'cex\'].sum()/1e9:,.2f}B")\nlog_line(section, "")\nlog_line(section, "Top 5 levels by hedging impact:")\nlog_line(section, top_hedging_impact_display.to_string(index=False))\n', '# 5) Unified signal\nstate = init_state()\nsection = "5) Unified signal"\nreset_section(section)\n\ngamma_regime = state.get(\'gamma_regime\', \'NEGATIVE\')\nsma_regime = state.get(\'sma_regime\', \'BULL\')\nvwap_position = state.get(\'vwap_position\', \'ABOVE\')\n\ndef generate_signal(gamma, sma, vwap):\n    if gamma == \'POSITIVE\':\n        vol = \'LOW / MEAN REVERTING\'\n        if sma == \'BULL\' and vwap == \'ABOVE\':\n            return \'LONG (TREND + SUPPORT)\', vol\n        elif sma == \'BULL\' and vwap == \'BELOW\':\n            return \'BUY DIP -> VWAP\', vol\n        elif sma == \'BEAR\' and vwap == \'BELOW\':\n            return \'SHORT RALLIES\', vol\n        else:\n            return \'CHOP / NO TRADE\', vol\n    else:\n        vol = \'HIGH / TRENDING\'\n        if sma == \'BULL\' and vwap == \'ABOVE\':\n            return \'MOMENTUM LONG\', vol\n        elif sma == \'BEAR\' and vwap == \'BELOW\':\n            return \'MOMENTUM SHORT\', vol\n        elif vwap == \'ABOVE\':\n            return \'UPSIDE SQUEEZE RISK\', vol\n        elif vwap == \'BELOW\':\n            return \'DOWNSIDE ACCELERATION\', vol\n        else:\n            return \'UNSTABLE / NO TRADE\', vol\n\nsignal, vol_profile = generate_signal(gamma_regime, sma_regime, vwap_position)\nstate.update({\'signal\': signal, \'structural_bias\': signal, \'vol_profile\': vol_profile})\n\nlog_line(section, "===== EXECUTION MODEL OUTPUT =====")\nlog_line(section, f"Structural Bias: {state.get(\'structural_bias\', state.get(\'signal\', \'Wait\'))}")\nlog_line(section, f"Execution State: {state.get(\'execution_state\', state.get(\'alert_state\', \'Wait\'))}")\nlog_line(section, f"Gamma Regime: {gamma_regime}")\nlog_line(section, f"SMA Regime: {sma_regime}")\nlog_line(section, f"VWAP Position: {vwap_position}")\nlog_line(section, f"Volatility: {vol_profile}")\nlog_line(section, f"TRADE SIGNAL: {signal}")\n', '# 6) Trigger rules with participation, live execution gates, alert state, and exit logic\nstate = init_state()\nsection = "6) Trigger rules"\nreset_section(section)\n\nintraday = state.get(\'intraday\')\nsignal = state.get(\'signal\')\ngamma_regime = state.get(\'gamma_regime\', \'NEGATIVE\')\ntrade_flow_bias = state.get(\'trade_flow_bias\', np.nan)\ntrade_flow_bias_recent = state.get(\'trade_flow_bias_recent\', np.nan)\ntrade_flow_bias_weighted = state.get(\'trade_flow_bias_weighted\', np.nan)\ntrade_bias_label = state.get(\'trade_bias_label\', \'unavailable\')\ntrade_bias_divergence = state.get(\'trade_bias_divergence\', \'Unknown\')\npin_pressure = state.get(\'pin_pressure\', np.nan)\npin_pressure_label = state.get(\'pin_pressure_label\', \'Unknown\')\nintraday_regime = state.get(\'intraday_regime\', \'Structural Gamma\')\ntop_hedging_impact = state.get(\'top_hedging_impact\', pd.DataFrame(columns=[\'strike\']))\ntotal_es_flow = state.get(\'total_es_flow\', 0.0)\nmarket_data_mode = state.get(\'market_data_mode\')\nvwap_session_type = state.get(\'vwap_session_type\')\nspread_regime = state.get(\'spread_regime\', \'Unavailable\')\n\nif intraday is None or signal is None:\n    raise ValueError("Missing prerequisites. Run cells 3, 4, and 5 first.")\n\nintraday = intraday.copy()\nintraday[\'avg_vol_20\'] = intraday[\'volume\'].rolling(20).mean()\nintraday[\'delta\'] = intraday[\'close\'] - intraday[\'open\']\n\nrecent = intraday.tail(min(TRIGGER_LOOKBACK_BARS, max(len(intraday)-1, 1)))\nbreakout = float(recent[\'high\'].max())\nlatest = intraday.iloc[-1]\np = float(latest[\'close\'])\nvwap = float(latest[\'VWAP\'])\nlatest_vol = float(latest[\'volume\'])\navg_vol = float(intraday[\'volume\'].tail(min(TRIGGER_LOOKBACK_BARS, len(intraday))).mean())\n\ncandle_buy_ratio = float((recent.loc[recent[\'delta\'] > 0, \'volume\'].sum()) / max(recent[\'volume\'].sum(), 1.0))\ntrade_flow_component = 0.50 if np.isnan(trade_flow_bias_weighted) else float(trade_flow_bias_weighted)\ntrade_flow_recent_component = 0.50 if np.isnan(trade_flow_bias_recent) else float(trade_flow_bias_recent)\n# tighter contradiction handling: emphasize recent tape and shrink stale session-flow influence\nbuy_ratio = 0.35 * candle_buy_ratio + 0.65 * trade_flow_recent_component\n\n\nvelocity_1m = state.get(\'velocity_1m\', 0.0)\nvelocity_5m = state.get(\'velocity_5m\', 0.0)\nmomentum_state = "Accelerating" if velocity_5m > 0.0005 else ("Fading" if velocity_5m < -0.0005 else "Flat")\nFAILED_LONG_LOOKBACK_BARS = 3\n\nstructural_bias = signal\nis_long_context = structural_bias in {"MOMENTUM LONG", "LONG (TREND + SUPPORT)", "BUY DIP -> VWAP"}\nis_downside_context = structural_bias in {"DOWNSIDE ACCELERATION", "MOMENTUM SHORT", "SHORT RALLIES"}\n\nvolume_spike = (latest_vol / avg_vol) if avg_vol > 0 else 0.0\nvolume_component = min(max((volume_spike - 1.0) / 0.5, 0.0), 1.0)\n\nif is_long_context:\n    direction_component = min(max((buy_ratio - 0.50) / 0.10, 0.0), 1.0)\nelse:\n    direction_component = min(max((0.50 - buy_ratio) / 0.10, 0.0), 1.0)\n\ninteraction_component = volume_component * direction_component\nparticipation_score = 0.25 * volume_component + 0.25 * direction_component + 0.50 * interaction_component\n\nif participation_score >= 0.75:\n    participation_quality = "STRONG"\nelif participation_score >= 0.50:\n    participation_quality = "MODERATE"\nelse:\n    participation_quality = "WEAK"\n\nvolume_ok = volume_spike >= 1.10\ndirection_ok = buy_ratio >= 0.52 if is_long_context else buy_ratio <= 0.48\nparticipation_confirmed = volume_ok and direction_ok and participation_score >= 0.50\n\nlive_session_confirmed = (\n    market_data_mode == "realtime" and\n    vwap_session_type == "current_session"\n)\nvelocity_confirmed_long = velocity_5m > 0 and velocity_1m >= 0\nspread_ok = spread_regime in {"Tight", "Normal"}\ndistance_to_breakout = abs(p - breakout) / breakout if breakout > 0 else np.nan\ndistance_to_vwap = abs(p - vwap) / vwap if vwap > 0 else np.nan\nlocation_ok = ((not np.isnan(distance_to_breakout) and distance_to_breakout <= 0.003) or\n               (not np.isnan(distance_to_vwap) and distance_to_vwap <= 0.003))\n\nlatest_close = p\nbreakout_buffer = breakout * 0.999\nabove_breakout_now = latest_close > breakout\nabove_breakout_two_bars = False\nif len(intraday) >= 2:\n    above_breakout_two_bars = bool((intraday[\'close\'].tail(2).values > breakout).all())\nbelow_vwap_now = latest_close < vwap\nbelow_vwap_two_bars = False\nif len(intraday) >= 2:\n    below_vwap_two_bars = bool((intraday[\'close\'].tail(2).values < intraday[\'VWAP\'].tail(2).values).all())\ndownside_velocity_confirmed = velocity_5m < 0\nvwap_failure = below_vwap_now and (below_vwap_two_bars or downside_velocity_confirmed)\n\n# Entry precision / slippage / false-start controls\nextension_from_vwap = max((vwap - latest_close) / vwap, 0.0) if vwap > 0 else np.nan\nlong_extension_from_breakout = max((latest_close - breakout) / breakout, 0.0) if breakout > 0 else np.nan\ndownside_extension_ok = (not np.isnan(extension_from_vwap)) and extension_from_vwap <= 0.0025\nlong_extension_ok = (not np.isnan(long_extension_from_breakout)) and long_extension_from_breakout <= 0.0020\ndownside_persistence_confirmed = bool(below_vwap_two_bars)\nlong_persistence_confirmed = bool(above_breakout_two_bars)\nretest_failure_confirmed = False\nif len(recent) >= 5:\n    recent_retest_high = float(recent[\'high\'].tail(5).max())\n    retest_failure_confirmed = (recent_retest_high >= vwap * 0.999) and below_vwap_now and downside_velocity_confirmed\nslippage_guard_ok = downside_extension_ok if is_downside_context else long_extension_ok\nfalse_start_guard_ok = (below_vwap_two_bars and downside_velocity_confirmed and (buy_ratio <= 0.48 or trade_flow_recent_component <= 0.48)) if is_downside_context else (above_breakout_two_bars and velocity_5m > 0)\n\n# Optional edge state: failed long -> short bias candidate\nrecent_velocity_flip_negative = False\nif len(intraday) >= FAILED_LONG_LOOKBACK_BARS + 1:\n    recent_vel = intraday[\'velocity_1m\'].tail(FAILED_LONG_LOOKBACK_BARS + 1).fillna(0)\n    recent_velocity_flip_negative = bool((recent_vel.iloc[-1] < 0) and (recent_vel.iloc[:-1].max() > 0))\n\nfailed_long_short_bias_candidate = (\n    is_long_context and\n    participation_score < 0.30 and\n    recent_velocity_flip_negative and\n    below_vwap_now\n)\n\nrecent_high_breach = float(recent[\'high\'].max()) > breakout\nfailed_hold = latest_close < breakout_buffer\nweak_participation = (participation_confirmed is False and participation_quality == "WEAK")\nfalse_breakout_alert = recent_high_breach and failed_hold and weak_participation\n\nnegative_gamma = gamma_regime == "NEGATIVE"\ndirectional_weakness = (buy_ratio < 0.48 or direction_component > 0.50)\ndownside_acceleration_alert = vwap_failure and negative_gamma and live_session_confirmed and spread_ok and location_ok and directional_weakness and false_start_guard_ok\n\nentry_blocked_by_velocity_conflict = (is_long_context and velocity_5m < 0)\n\nif is_long_context:\n    if participation_confirmed and live_session_confirmed and velocity_confirmed_long and spread_ok and location_ok and long_extension_ok and above_breakout_two_bars and not entry_blocked_by_velocity_conflict:\n        execution_state = "Live Long"\n        actionable = True\n    elif failed_long_short_bias_candidate:\n        execution_state = "Failed Long -> Short Bias Candidate"\n        actionable = False\n    elif participation_confirmed:\n        execution_state = "Primed Long"\n        actionable = False\n    elif false_breakout_alert:\n        execution_state = "False Breakout / Fade"\n        actionable = False\n    elif downside_acceleration_alert:\n        execution_state = "Downside Acceleration"\n        actionable = False\n    else:\n        execution_state = "Wait"\n        actionable = False\nelif is_downside_context:\n    if downside_acceleration_alert and participation_confirmed and slippage_guard_ok and (retest_failure_confirmed or below_vwap_two_bars):\n        execution_state = "Downside Acceleration"\n        actionable = True\n    elif participation_confirmed:\n        execution_state = "Primed Downside"\n        actionable = False\n    else:\n        execution_state = "Wait"\n        actionable = False\nelse:\n    execution_state = "Wait"\n    actionable = False\n\nhigher_strikes = sorted([float(x) for x in top_hedging_impact[\'strike\'].tolist() if float(x) > state.get(\'S\', 0)])\nlower_strikes = sorted([float(x) for x in top_hedging_impact[\'strike\'].tolist() if float(x) < state.get(\'S\', 0)], reverse=True)\ntarget_level = (\n    higher_strikes[0] if execution_state == "Live Long" and higher_strikes else\n    lower_strikes[0] if execution_state in {"False Breakout / Fade", "Downside Acceleration", "Primed Downside", "Failed Long -> Short Bias Candidate"} and lower_strikes else\n    np.nan\n)\nparticipation_decay_exit = participation_score < 0.35\nvelocity_reversal_exit = (execution_state == "Live Long" and velocity_5m < 0) or (execution_state in {"False Breakout / Fade", "Downside Acceleration"} and velocity_5m > 0)\ndealer_push_direction = "Downside" if total_es_flow < 0 else ("Upside" if total_es_flow > 0 else "Neutral")\nexecution_readiness = "Live" if (live_session_confirmed and actionable) else ("Delayed / Development Only" if not live_session_confirmed else "Not Ready")\n\nif execution_state in {"Live Long", "Primed Long", "Wait"} and is_long_context:\n    entry_rule = f\'Open long only if price breaks above {breakout:.2f} with participation confirmation or pulls back to VWAP {vwap:.2f} and holds.\'\n    invalid_if = f\'Stand down if price loses VWAP {vwap:.2f}.\'\n    entry_price = breakout if execution_state == "Live Long" else np.nan\n    stop_price = round(vwap * (1 - STOP_BUFFER_PCT), 2) if execution_state == "Live Long" else np.nan\nelif execution_state == "False Breakout / Fade":\n    entry_rule = f\'Open fade only if breakout above {breakout:.2f} fails and price slips back under that level with weak participation.\'\n    invalid_if = f\'Fade invalid if price reclaims and holds above {breakout:.2f}.\'\n    entry_price = breakout_buffer\n    stop_price = round(breakout * (1 + STOP_BUFFER_PCT), 2)\nelif execution_state == "Failed Long -> Short Bias Candidate":\n    entry_rule = f\'Watch for failed-long confirmation: if price stays below VWAP {vwap:.2f} and short-term momentum remains negative, prepare for downside transition.\'\n    invalid_if = f\'Short-bias candidate invalid if price reclaims and holds above VWAP {vwap:.2f}.\'\n    entry_price = np.nan\n    stop_price = np.nan\nelif execution_state in {"Downside Acceleration", "Primed Downside"} or is_downside_context:\n    entry_rule = f\'Open downside only if price remains below VWAP {vwap:.2f}, downside velocity stays negative, and participation continues to support the move.\'\n    invalid_if = f\'Downside setup invalid if price reclaims VWAP {vwap:.2f}.\'\n    entry_price = vwap if execution_state == "Downside Acceleration" else np.nan\n    stop_price = round(vwap * (1 + STOP_BUFFER_PCT), 2) if execution_state == "Downside Acceleration" else np.nan\nelse:\n    entry_rule = f\'Wait for cleaner alignment around breakout {breakout:.2f} and VWAP {vwap:.2f}.\'\n    invalid_if = f\'Stand down until price and participation re-align.\'\n    entry_price = np.nan\n    stop_price = np.nan\n\nplan = {\n    \'actionable\': actionable,\n    \'setup_type\': \'LONG\' if execution_state in {"Live Long", "Primed Long"} else (\'SHORT_BIAS_CANDIDATE\' if execution_state == "Failed Long -> Short Bias Candidate" else (\'FADE\' if execution_state == "False Breakout / Fade" else (\'DOWNSIDE\' if execution_state in {"Downside Acceleration", "Primed Downside"} else \'NONE\'))),\n    \'entry_rule\': entry_rule,\n    \'entry_price\': entry_price,\n    \'stop_price\': stop_price,\n    \'target_price\': target_level if actionable else np.nan,\n    \'invalid_if\': invalid_if,\n    \'volume_confirmation\': participation_confirmed,\n    \'volume_spike\': volume_spike,\n    \'buy_ratio\': buy_ratio,\n    \'trade_flow_bias\': trade_flow_component,\n    \'trade_flow_bias_session\': trade_flow_bias,\n    \'trade_flow_bias_recent\': trade_flow_recent_component,\n    \'trade_bias_divergence\': trade_bias_divergence,\n    \'participation_score\': participation_score,\n    \'market_data_mode\': market_data_mode,\n    \'vwap_session_type\': vwap_session_type,\n    \'volume_component\': volume_component,\n    \'direction_component\': direction_component,\n    \'interaction_component\': interaction_component,\n    \'participation_quality\': participation_quality,\n    \'participation_confirmed\': participation_confirmed,\n    \'structural_bias\': structural_bias,\n    \'execution_state\': execution_state,\n    \'alert_state\': execution_state,\n    \'execution_readiness\': execution_readiness,\n    \'live_session_confirmed\': live_session_confirmed,\n    \'velocity_confirmed_long\': velocity_confirmed_long,\n    \'slippage_guard_ok\': slippage_guard_ok,\n    \'false_start_guard_ok\': false_start_guard_ok,\n    \'extension_from_vwap\': extension_from_vwap,\n    \'long_extension_from_breakout\': long_extension_from_breakout,\n    \'downside_persistence_confirmed\': downside_persistence_confirmed,\n    \'long_persistence_confirmed\': long_persistence_confirmed,\n    \'retest_failure_confirmed\': retest_failure_confirmed,\n    \'recent_velocity_flip_negative\': recent_velocity_flip_negative,\n    \'failed_long_short_bias_candidate\': failed_long_short_bias_candidate,\n    \'spread_ok\': spread_ok,\n    \'location_ok\': location_ok,\n    \'distance_to_breakout\': distance_to_breakout,\n    \'distance_to_vwap\': distance_to_vwap,\n    \'below_vwap_now\': below_vwap_now,\n    \'below_vwap_two_bars\': below_vwap_two_bars,\n    \'downside_velocity_confirmed\': downside_velocity_confirmed,\n    \'false_breakout_alert\': false_breakout_alert,\n    \'downside_acceleration_alert\': downside_acceleration_alert,\n    \'velocity_1m\': velocity_1m,\n    \'velocity_5m\': velocity_5m,\n    \'momentum_state\': momentum_state,\n    \'pin_pressure\': pin_pressure,\n    \'pin_pressure_label\': pin_pressure_label,\n    \'intraday_regime\': intraday_regime,\n    \'dealer_push_direction\': dealer_push_direction,\n    \'exit_if_participation_rolls_over\': participation_decay_exit,\n    \'exit_if_velocity_reverses\': velocity_reversal_exit,\n    \'entry_blocked_by_velocity_conflict\': entry_blocked_by_velocity_conflict,\n    \'live_trading_mode\': LIVE_TRADING_MODE,\n    \'notes\': (\n        \'Bullish structure is present, but execution quality is not fully aligned yet.\' if execution_state in {\'Wait\',\'Primed Long\'} and is_long_context else\n        \'Downside structure is present, but execution quality is not fully aligned yet.\' if execution_state in {\'Wait\',\'Primed Downside\'} and is_downside_context else\n        \'Live session and execution filters aligned.\' if execution_state in {\'Live Long\',\'Downside Acceleration\'} else\n        \'Downside structure is present, but participation is too weak to press the move.\' if execution_state == \'Wait\' and is_downside_context else \'Directional failure logic is active.\'\n    )\n}\n\nif LIVE_TRADING_MODE and not live_session_confirmed:\n    plan[\'actionable\'] = False\n\nstate.update({\n    \'plan\': plan,\n    \'alert_state\': execution_state,\n    \'execution_state\': execution_state,\n    \'execution_readiness\': execution_readiness,\n    \'structural_bias\': structural_bias,\n    \'buy_ratio\': buy_ratio,\n    \'trade_flow_component\': trade_flow_component,\n    \'participation_score\': participation_score,\n    \'participation_quality\': participation_quality,\n    \'participation_confirmed\': participation_confirmed,\n    \'target_level\': target_level,\n    \'dealer_push_direction\': dealer_push_direction,\n    \'momentum_state\': momentum_state,\n    \'participation_decay_exit\': participation_decay_exit,\n    \'velocity_reversal_exit\': velocity_reversal_exit,\n    \'breakout\': breakout,\n    \'vwap\': vwap,\n})\n\nlog_line(section, "===== TRIGGER RULES =====")\nrounded_fields = {\'volume_spike\',\'buy_ratio\',\'trade_flow_bias\',\'trade_flow_bias_session\',\'trade_flow_bias_recent\',\'participation_score\',\'volume_component\',\'direction_component\',\'interaction_component\',\'velocity_1m\',\'velocity_5m\',\'pin_pressure\',\'distance_to_breakout\',\'distance_to_vwap\',\'extension_from_vwap\',\'long_extension_from_breakout\'}\nfor k, v in plan.items():\n    if k in rounded_fields:\n        try:\n            log_line(section, f"{k}: {float(v):.4f}")\n        except Exception:\n            log_line(section, f"{k}: {v}")\n    else:\n        log_line(section, f"{k}: {v}")\n', '# 7) Plain-language actionable intelligence\nstate = init_state()\nsection = "7) Actionable intelligence"\nreset_section(section)\n\nrequired = [\'capture_pct_rows\',\'capture_pct_oi\',\'market_data_mode\',\'vwap_session_type\',\'intraday_session_date\',\'S\',\'true_pin_level\',\'flip_context\',\'zero_flip_context\',\'gamma_regime\',\'total_es_flow\',\'zero_dte_share\',\'sma_regime\',\'vwap_position\',\'signal\',\'call_wall\',\'put_wall\',\'call_gex_wall\',\'put_gex_wall\',\'top_hedging_impact\',\'top_hedging_impact_display\',\'plan\']\nmissing = [k for k in required if k not in state]\nif missing:\n    raise ValueError(f"Missing prerequisites for actionable intelligence: {missing}")\n\ndef classify_es_flow_bucket(x):\n    ax = abs(x)\n    if ax < 10000:\n        return "light", "dealer hedging impact should be limited unless other forces dominate"\n    if ax < 50000:\n        return "moderate", "dealer hedging should matter, but it is not overwhelming"\n    if ax < 150000:\n        return "large", "dealer hedging should be a meaningful driver of intraday extension or suppression"\n    return "very large", "dealer hedging should be a major force in the tape"\n\ndef signed_flow_interpretation(x):\n    if x > 0:\n        return "dealer hedging should damp moves and lean against price extension"\n    if x < 0:\n        return "dealer hedging should amplify moves and chase direction"\n    return "dealer hedging impact looks neutral"\n\ndef zero_dte_share_label(zero_share):\n    az = abs(zero_share)\n    if az < 0.10:\n        return "small", "same-day positioning is a small part of the overall setup"\n    if az < 0.30:\n        return "meaningful", "same-day positioning matters, but it is not the main driver"\n    if az < 0.60:\n        return "large", "same-day positioning is a major part of the setup"\n    return "dominant", "same-day positioning is dominating the setup"\n\ndef wall_asymmetry_text(call_wall_val, put_wall_val):\n    if np.isnan(call_wall_val) or np.isnan(put_wall_val):\n        return "wall structure is incomplete, so hedging asymmetry cannot be assessed cleanly"\n    if abs(call_wall_val - put_wall_val) < 1e-9:\n        return "hedging pressure is concentrated at the same strike for both sides"\n    diff = abs(call_wall_val - put_wall_val)\n    if diff <= 50:\n        return "hedging pressure is only mildly asymmetric"\n    if diff <= 200:\n        return "hedging pressure is asymmetric"\n    return "hedging pressure is strongly asymmetric"\n\ndef participation_opinion_text(volume_component, direction_component, participation_quality, structural_bias, buy_ratio, velocity_5m):\n    long_bias = structural_bias in {"MOMENTUM LONG", "LONG (TREND + SUPPORT)", "BUY DIP -> VWAP"}\n    downside_bias = structural_bias in {"DOWNSIDE ACCELERATION", "MOMENTUM SHORT", "SHORT RALLIES"}\n\n    absorption_risk = (\n        downside_bias\n        and buy_ratio > 0.60\n        and velocity_5m < 0\n    )\n\n    if participation_score >= 0.65:\n        return "Strong Participation: Move Is Well Sponsored"\n\n    if direction_component == 0 and volume_component == 0:\n        if absorption_risk:\n            return "Participation Opposes Setup: Flow And Volume Both Misaligned. Potential Absorption — Sellers Are Not In Control."\n        return "Participation Opposes Setup: Flow And Volume Both Misaligned"\n\n    if direction_component == 0:\n        if absorption_risk:\n            return "Flow Opposes Move: Potential Absorption — Sellers Are Not In Control"\n        return "Flow Opposes Move: Tape Is Trading Against Setup Direction"\n\n    if volume_component == 0:\n        if long_bias:\n            return "Low-Conviction Rally: Direction Is Up But Participation Is Thin"\n        if downside_bias:\n            return "Weak Sell Pressure: Downside Lacks Real Sponsorship"\n\n    if volume_component > 0.7 and direction_component < 0.3:\n        return "Gears Are Grinding: High Volume And Weak Direction."\n\n    if direction_component > 0.7 and volume_component < 0.3:\n        return "Fake Pump: Strong Direction And Weak Volume."\n\n    if participation_score < 0.35:\n        return "Weak Participation: Setup Not Reliably Sponsored"\n\n    return "Moderate Participation: Conditions Are Acceptable But Not Ideal"\n\ndef move_real_answer(participation_confirmed, spread_regime, trade_bias_label, structural_bias):\n    long_bias = structural_bias in {"MOMENTUM LONG", "LONG (TREND + SUPPORT)", "BUY DIP -> VWAP"}\n    downside_bias = structural_bias in {"DOWNSIDE ACCELERATION", "MOMENTUM SHORT", "SHORT RALLIES"}\n    flow_aligned = (\n        (long_bias and trade_bias_label == "BUY DOMINANT") or\n        (downside_bias and trade_bias_label == "SELL DOMINANT")\n    )\n    if participation_confirmed and spread_regime != "Wide" and flow_aligned:\n        return "Yes — the move looks real because participation, spread, and trade flow are directionally aligned."\n    if participation_confirmed:\n        return "Mostly yes — participation is present, but market microstructure or trade flow is not perfectly aligned with the setup direction."\n    return "Not yet — activity is present, but the move is not convincingly backed by directional participation."\n\ndef breakout_or_trap_answer(execution_state):\n    if execution_state == "Live Long":\n        return "Breakout is favored over trap, because participation, velocity, and market-hours checks are aligned."\n    if execution_state == "Primed Long":\n        return "Breakout is structurally favored, but live execution confirmation is still missing."\n    if execution_state == "Failed Long -> Short Bias Candidate":\n        return "The upside attempt looks vulnerable; weak-long behavior is starting to transition into potential downside."\n    if execution_state == "False Breakout / Fade":\n        return "Trap is favored — the breakout failed without real participation."\n    if execution_state == "Downside Acceleration":\n        return "The setup has shifted from breakout logic to downside trend logic and the downside trigger is active."\n    if execution_state == "Primed Downside":\n        return "Downside is structurally favored, but confirmation is not yet strong enough to press the move."\n    return "Unclear — breakout or downside conditions exist structurally, but not behaviorally."\n\ndef momentum_answer(momentum_state, velocity_5m):\n    if momentum_state == "Accelerating":\n        return f"Momentum is accelerating; 5-minute velocity is running at {velocity_5m:.4%}."\n    if momentum_state == "Fading":\n        return f"Momentum is dying; 5-minute velocity has rolled over to {velocity_5m:.4%}."\n    return "Momentum is flat to mixed; velocity is not strong enough to confirm extension."\n\ndef dealer_push_answer(total_es_flow, gamma_regime):\n    direction = "downside" if total_es_flow < 0 else ("upside" if total_es_flow > 0 else "neutral")\n    return f"Dealers are still pushing {direction} through a {gamma_regime.lower()}-gamma hedging profile."\n\ndef participation_rollover_answer(participation_decay_exit):\n    return "Yes — participation has rolled over enough that you should think about exiting or standing down." if participation_decay_exit else "No — participation has not rolled over enough to force an exit by itself."\n\nS = state[\'S\']\ntrue_pin_level = state[\'true_pin_level\']\ndistance_to_pin = abs(S - true_pin_level) if not np.isnan(true_pin_level) else np.nan\npin_context = (\n    "near the true pin level" if not np.isnan(distance_to_pin) and distance_to_pin <= 25 else\n    "within reach of the true pin level" if not np.isnan(distance_to_pin) and distance_to_pin <= 100 else\n    "well away from the true pin level"\n)\n\nraw_walls_same = (not np.isnan(state[\'call_wall\'])) and (not np.isnan(state[\'put_wall\'])) and abs(state[\'call_wall\'] - state[\'put_wall\']) < 1e-9\ngex_walls_same = (not np.isnan(state[\'call_gex_wall\'])) and (not np.isnan(state[\'put_gex_wall\'])) and abs(state[\'call_gex_wall\'] - state[\'put_gex_wall\']) < 1e-9\n\nflow_bucket, flow_meaning = classify_es_flow_bucket(state[\'total_es_flow\'])\n_, zero_meaning = zero_dte_share_label(state[\'zero_dte_share\'])\ngex_wall_meaning = wall_asymmetry_text(state[\'call_gex_wall\'], state[\'put_gex_wall\'])\nparticipation_opinion = participation_opinion_text(state[\'plan\'][\'volume_component\'], state[\'plan\'][\'direction_component\'], state[\'plan\'][\'participation_quality\'], state[\'structural_bias\'], state[\'buy_ratio\'], state[\'velocity_5m\'])\n\nstory_lines = []\nstory_lines.append("===== ACTIONABLE INTELLIGENCE =====")\nstory_lines.append(f"Structural Bias: {state[\'structural_bias\']}.")\nstory_lines.append(f"Execution State: {state[\'execution_state\']}.")\nstory_lines.append(f"Execution Readiness: {state[\'execution_readiness\']}.")\nstory_lines.append(f"Full chain capture looks {\'complete enough for modeling\' if not state.get(\'truncation_risk\') else \'at risk of truncation\'}, with {fmt_num(state[\'capture_pct_rows\'])}% of rows and {fmt_num(state[\'capture_pct_oi\'])}% of open interest retained after intelligent downsampling.")\nstory_lines.append(f"Intraday execution data is running in {state[\'market_data_mode\']} mode using {state[\'vwap_session_type\']} from {state[\'intraday_session_date\']}.")\nstory_lines.append(f"Spot is {pin_context}; SPX spot is {fmt_num(S)} versus true pin {fmt_num(true_pin_level, 0)}.")\nstory_lines.append(f"Flip context: {state[\'flip_context\']}. 0DTE flip context: {state[\'zero_flip_context\']}.")\nstory_lines.append(f"Gamma regime is {state[\'gamma_regime\'].lower()}, so {signed_flow_interpretation(state[\'total_es_flow\'])}.")\nstory_lines.append(f"Total ES flow for a 1% move is {fmt_int(state[\'total_es_flow\'])} contracts, which is a {flow_bucket} flow estimate; {flow_meaning}.")\nstory_lines.append(f"0DTE contributes {fmt_num(abs(state[\'zero_dte_share\'])*100)}% of total gamma impact by magnitude, so {zero_meaning}.")\nstory_lines.append(f"Intraday regime is {state[\'intraday_regime\']}, pin pressure is {state[\'pin_pressure_label\'].lower()}, spread regime is {state[\'spread_regime\']}, and trade flow is {state[\'trade_bias_label\']} ({state.get(\'trade_bias_divergence\',\'Unknown\')}).")\nstory_lines.append(f"SMA regime is {state[\'sma_regime\'].lower()} and price is {state[\'vwap_position\'].lower()} VWAP, which supports the structural bias: {state[\'signal\']}.")\nif raw_walls_same:\n    story_lines.append(f"Raw OI call and put walls both sit at {fmt_num(state[\'call_wall\'],0)}, which suggests a major structural open-interest magnet there.")\nelse:\n    story_lines.append(f"Raw OI walls are split: call wall {fmt_num(state[\'call_wall\'],0)} and put wall {fmt_num(state[\'put_wall\'],0)}, which suggests open-interest pressure is split across different strikes.")\nif gex_walls_same:\n    story_lines.append(f"GEX-weighted walls also converge at {fmt_num(state[\'call_gex_wall\'],0)}, which means {gex_wall_meaning}.")\nelse:\n    story_lines.append(f"GEX-weighted walls differ: call wall {fmt_num(state[\'call_gex_wall\'],0)} and put wall {fmt_num(state[\'put_gex_wall\'],0)}, which means {gex_wall_meaning}.")\ntop1 = state[\'top_hedging_impact\'].iloc[0] if len(state[\'top_hedging_impact\']) else None\nif top1 is not None:\n    direction = "negative" if top1[\'gex\'] < 0 else "positive"\n    story_lines.append(f"The single biggest hedging-impact level is {fmt_num(top1[\'strike\'],0)} with {direction} gamma of {fmt_num(top1[\'gex\']/1e9)}B.")\n    story_lines.append("Top 5 Levels By Hedging Impact:")\n    story_lines.append(state[\'top_hedging_impact_display\'].to_string(index=False))\nstory_lines.append(f"Participation score is {fmt_num(state[\'participation_score\'])} from volume spike {fmt_num(state[\'plan\'][\'volume_spike\'])} and buy ratio {fmt_num(state[\'buy_ratio\'])}, so participation is {\'confirmed\' if state[\'participation_confirmed\'] else \'not confirmed strongly enough\'}.")\nstory_lines.append(f"Participation Model Opinion: {participation_opinion}")\nstory_lines.append(f"Operationally: {state[\'plan\'][\'entry_rule\']}")\nif state[\'execution_state\'] == "Failed Long -> Short Bias Candidate":\n    story_lines.append(f"Entry precision guards: slippage guard = {state[\'plan\'].get(\'slippage_guard_ok\')}, false-start guard = {state[\'plan\'].get(\'false_start_guard_ok\')}, recent velocity flip negative = {state[\'plan\'].get(\'recent_velocity_flip_negative\')}, downside persistence confirmed = {state[\'plan\'].get(\'downside_persistence_confirmed\')}.")\nelif state[\'structural_bias\'] in {"MOMENTUM LONG", "LONG (TREND + SUPPORT)", "BUY DIP -> VWAP"}:\n    story_lines.append(f"Entry precision guards: slippage guard = {state[\'plan\'].get(\'slippage_guard_ok\')}, false-start guard = {state[\'plan\'].get(\'false_start_guard_ok\')}, long persistence confirmed = {state[\'plan\'].get(\'long_persistence_confirmed\')}.")\nelif state[\'structural_bias\'] in {"DOWNSIDE ACCELERATION", "MOMENTUM SHORT", "SHORT RALLIES"}:\n    story_lines.append(f"Entry precision guards: slippage guard = {state[\'plan\'].get(\'slippage_guard_ok\')}, false-start guard = {state[\'plan\'].get(\'false_start_guard_ok\')}, downside persistence confirmed = {state[\'plan\'].get(\'downside_persistence_confirmed\')}, retest failure confirmed = {state[\'plan\'].get(\'retest_failure_confirmed\')}.")\nelse:\n    story_lines.append(f"Entry precision guards: slippage guard = {state[\'plan\'].get(\'slippage_guard_ok\')}, false-start guard = {state[\'plan\'].get(\'false_start_guard_ok\')}.")\nstory_lines.append(f"Risk line: {state[\'plan\'][\'invalid_if\']}")\nstory_lines.append("Five Decision Questions:")\nstory_lines.append(f"1. Is This Move Real? {move_real_answer(state[\'participation_confirmed\'], state[\'spread_regime\'], state[\'trade_bias_label\'], state[\'structural_bias\'])}")\nstory_lines.append(f"2. Is This A Breakout Or A Trap? {breakout_or_trap_answer(state[\'execution_state\'])}")\nstory_lines.append(f"3. Is Momentum Accelerating Or Dying? {momentum_answer(state[\'momentum_state\'], state[\'velocity_5m\'])}")\nstory_lines.append(f"4. Are Dealers Still Pushing? {dealer_push_answer(state[\'total_es_flow\'], state[\'gamma_regime\'])}")\nstory_lines.append(f"5. Has Participation Rolled Over? {participation_rollover_answer(state[\'participation_decay_exit\'])}")\nstory_lines.append(f"Exit logic now points to target {fmt_num(state[\'target_level\'],0)} when available, exit on participation rollover = {state[\'participation_decay_exit\']}, and exit on velocity reversal = {state[\'velocity_reversal_exit\']}.")\nstory_lines.append(f"Bottom line: the tape is being framed as {state[\'vol_profile\'].lower()}, but the execution engine says {state[\'execution_state\'].lower()}.")\n\nstate[\'story_lines\'] = story_lines\nfor line in story_lines:\n    log_line(section, line)\n', '# 8) Final consolidated report for downstream use\nstate = init_state()\nsection = "8) Final consolidated report"\nreset_section(section)\n\nrun_ts = datetime.now(pytz.timezone("America/New_York")).strftime("%Y-%m-%d %H:%M:%S %Z")\n\nordered_sections = [\n    "1) Load FULL chain safely and compute TRUE days_to_expiry",\n    "2) Resolve spot with hierarchy: SPX snapshot -> SPY proxy -> parity",\n    "2A) Chain capture diagnostics",\n    "3) Price proxy data for SMA / VWAP",\n    "4) Gamma engine + corrected 0DTE outputs",\n    "5) Unified signal",\n    "6) Trigger rules",\n    "7) Actionable intelligence",\n]\n\nreport_lines = []\nfor sec in ordered_sections:\n    report_lines.append(f"# {sec}")\n    report_lines.extend(state[\'reports\'].get(sec, ["Section not yet run."]))\n    report_lines.append("")\n\nreport_lines.append(f"Run Date and Time: {run_ts}")\n\nfinal_report = "\\n".join(report_lines)\nprint(final_report)\n\nreport_txt_path = Path(\'spx_execution_report.txt\')\nreport_txt_path.write_text(final_report, encoding=\'utf-8\')\n\ndef safe_float(x):\n    try:\n        if x is None or (isinstance(x, float) and math.isnan(x)):\n            return None\n        return float(x)\n    except Exception:\n        return None\n\nreport_json = {\n    \'execution_model\': {\n        \'gamma_regime\': state.get(\'gamma_regime\'),\n        \'sma_regime\': state.get(\'sma_regime\'),\n        \'vwap_position\': state.get(\'vwap_position\'),\n        \'volatility\': state.get(\'vol_profile\'),\n        \'structural_bias\': state.get(\'structural_bias\'),\n        \'trade_signal\': state.get(\'signal\'),\n        \'execution_state\': state.get(\'execution_state\'),\n        \'execution_readiness\': state.get(\'execution_readiness\'),\n        \'alert_state\': state.get(\'alert_state\'),\n    },\n    \'trigger_rules\': {k: (safe_float(v) if isinstance(v, (float, int, np.floating, np.integer)) else v) for k, v in state.get(\'plan\', {}).items()},\n    \'actionable_intelligence\': state.get(\'story_lines\', []),\n    \'run_date_time\': run_ts,\n}\nreport_json_path = Path(\'spx_execution_report.json\')\nreport_json_path.write_text(json.dumps(report_json, indent=2, default=str), encoding=\'utf-8\')\n\nstate[\'artifacts\'][\'report_txt\'] = str(report_txt_path.resolve())\nstate[\'artifacts\'][\'report_json\'] = str(report_json_path.resolve())\n\nlog_line(section, f"Saved text report to: {report_txt_path.resolve()}")\nlog_line(section, f"Saved JSON report to: {report_json_path.resolve()}")\n']


def build_env(api_key: str, live_trading_mode: bool = True) -> dict[str, Any]:
    env: dict[str, Any] = {}
    exec(CONSTANTS_CODE, env)
    env["API_KEY"] = api_key
    env["LIVE_TRADING_MODE"] = live_trading_mode
    exec(HELPERS_CODE, env)
    return env


def run_model(api_key: str, live_trading_mode: bool = True) -> tuple[dict[str, Any], dict[str, Any]]:
    if not api_key:
        raise ValueError("Missing Polygon API key.")
    env = build_env(api_key=api_key, live_trading_mode=live_trading_mode)

    original_cwd = os.getcwd()
    with TemporaryDirectory() as tmpdir:
        os.chdir(tmpdir)
        try:
            for code in SECTION_CODES:
                exec(code, env)
            report_json = env.get("report_json")
            state = env.get("state", {})
            if report_json is None:
                report_json = {
                    "execution_model": {
                        "gamma_regime": state.get("gamma_regime"),
                        "sma_regime": state.get("sma_regime"),
                        "vwap_position": state.get("vwap_position"),
                        "volatility": state.get("vol_profile"),
                        "structural_bias": state.get("structural_bias"),
                        "trade_signal": state.get("signal"),
                        "execution_state": state.get("execution_state"),
                        "execution_readiness": state.get("execution_readiness"),
                        "alert_state": state.get("alert_state"),
                    },
                    "trigger_rules": state.get("plan", {}),
                    "actionable_intelligence": state.get("story_lines", []),
                    "run_date_time": ""
                }
            return report_json, state
        finally:
            os.chdir(original_cwd)
